    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // fetchTicker
        //
        //     {
        //         "marketId":"BAT-AUD",
        //         "bestBid":"0.3751",
        //         "bestAsk":"0.377",
        //         "lastPrice":"0.3769",
        //         "volume24h":"56192.97613335",
        //         "volumeQte24h":"21179.13270465",
        //         "price24h":"0.0119",
        //         "pricePct24h":"3.26",
        //         "low24h":"0.3611",
        //         "high24h":"0.3799",
        //         "timestamp":"2020-08-09T18:28:23.280000Z"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "marketId");
        market = this.safeMarket(marketId, market, "-");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.parse8601(this.safeString(ticker, "timestamp"));
        Object last = this.safeString(ticker, "lastPrice");
        Object baseVolume = this.safeString(ticker, "volume24h");
        Object quoteVolume = this.safeString(ticker, "volumeQte24h");
        Object change = this.safeString(ticker, "price24h");
        Object percentage = this.safeString(ticker, "pricePct24h");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BtcmarketsCore.this.iso8601(timestamp) );
            put( "high", BtcmarketsCore.this.safeString(ticker, "high24h") );
            put( "low", BtcmarketsCore.this.safeString(ticker, "low") );
            put( "bid", BtcmarketsCore.this.safeString(ticker, "bestBid") );
            put( "bidVolume", null );
            put( "ask", BtcmarketsCore.this.safeString(ticker, "bestAsk") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", change );
            put( "percentage", percentage );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "info", ticker );
        }}, market);
    }

