    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // public fetchTrades
        //
        //     {
        //         "id":"6191646611",
        //         "price":"539.98",
        //         "amount":"0.5",
        //         "timestamp":"2020-08-09T15:21:05.016000Z",
        //         "side":"Ask"
        //     }
        //
        // private fetchMyTrades
        //
        //     {
        //         "id": "36014819",
        //         "marketId": "XRP-AUD",
        //         "timestamp": "2019-06-25T16:01:02.977000Z",
        //         "price": "0.67",
        //         "amount": "1.50533262",
        //         "side": "Ask",
        //         "fee": "0.00857285",
        //         "orderId": "3648306",
        //         "liquidityType": "Taker",
        //         "clientOrderId": "48"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(trade, "timestamp"));
        Object marketId = this.safeString(trade, "marketId");
        market = this.safeMarket(marketId, market, "-");
        Object feeCurrencyCode = ((Helpers.isTrue((Helpers.isEqual(Helpers.GetValue(market, "quote"), "AUD"))))) ? Helpers.GetValue(market, "quote") : Helpers.GetValue(market, "base");
        Object side = this.safeString(trade, "side");
        if (Helpers.isTrue(Helpers.isEqual(side, "Bid")))
        {
            side = "buy";
        } else if (Helpers.isTrue(Helpers.isEqual(side, "Ask")))
        {
            side = "sell";
        }
        Object id = this.safeString(trade, "id");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "amount");
        Object orderId = this.safeString(trade, "orderId");
        Object fee = null;
        Object feeCostString = this.safeString(trade, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", feeCurrencyCode );
            }};
        }
        Object takerOrMaker = this.safeStringLower(trade, "liquidityType");
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", id );
            put( "timestamp", timestamp );
            put( "datetime", BtcmarketsCore.this.iso8601(timestamp) );
            put( "order", orderId );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", null );
            put( "side", finalSide );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "takerOrMaker", takerOrMaker );
            put( "fee", finalFee );
        }}, market);
    }

