    /**
     * @method
     * @name btcmarkets#createOrder
     * @description create a trade order
     * @see https://docs.btcmarkets.net/v3/#tag/Order-Placement-APIs/paths/~1v3~1orders/post
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {float} [params.triggerPrice] the price at which a trigger order is triggered at
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            final Object finalSide = side;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "marketId", Helpers.GetValue(market, "id") );
                put( "amount", BtcmarketsCore.this.amountToPrecision(symbol, amount) );
                put( "side", ((Helpers.isTrue((Helpers.isEqual(finalSide, "buy"))))) ? "Bid" : "Ask" );
            }};
            Object lowercaseType = ((String)type).toLowerCase();
            Object orderTypes = this.safeValue(this.options, "orderTypes", new java.util.HashMap<String, Object>() {{
                put( "limit", "Limit" );
                put( "market", "Market" );
                put( "stop", "Stop" );
                put( "stop limit", "Stop Limit" );
                put( "take profit", "Take Profit" );
            }});
            Helpers.addElementToObject(request, "type", this.safeString(orderTypes, lowercaseType, type));
            Object priceIsRequired = false;
            Object triggerPriceIsRequired = false;
            if (Helpers.isTrue(Helpers.isEqual(lowercaseType, "limit")))
            {
                priceIsRequired = true;
            } else if (Helpers.isTrue(Helpers.isEqual(lowercaseType, "stop limit")))
            {
                triggerPriceIsRequired = true;
                priceIsRequired = true;
            } else if (Helpers.isTrue(Helpers.isEqual(lowercaseType, "take profit")))
            {
                triggerPriceIsRequired = true;
            } else if (Helpers.isTrue(Helpers.isEqual(lowercaseType, "stop")))
            {
                triggerPriceIsRequired = true;
            }
            if (Helpers.isTrue(priceIsRequired))
            {
                if (Helpers.isTrue(Helpers.isEqual(price, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(Helpers.add(Helpers.add(this.id, " createOrder() requires a price argument for a "), type), "order")) ;
                } else
                {
                    Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                }
            }
            if (Helpers.isTrue(triggerPriceIsRequired))
            {
                Object triggerPrice = this.safeNumber(parameters, "triggerPrice");
                parameters = this.omit(parameters, "triggerPrice");
                if (Helpers.isTrue(Helpers.isEqual(triggerPrice, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(Helpers.add(Helpers.add(this.id, " createOrder() requires a triggerPrice parameter for a "), type), "order")) ;
                } else
                {
                    Helpers.addElementToObject(request, "triggerPrice", this.priceToPrecision(symbol, triggerPrice));
                }
            }
            Object clientOrderId = this.safeString(parameters, "clientOrderId");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                Helpers.addElementToObject(request, "clientOrderId", clientOrderId);
            }
            parameters = this.omit(parameters, "clientOrderId");
            Object response = (this.privatePostOrders(this.extend(request, parameters))).join();
            //
            //     {
            //         "orderId": "7524",
            //         "marketId": "BTC-AUD",
            //         "side": "Bid",
            //         "type": "Limit",
            //         "creationTime": "2019-08-30T11:08:21.956000Z",
            //         "price": "100.12",
            //         "amount": "1.034",
            //         "openAmount": "1.034",
            //         "status": "Accepted",
            //         "clientOrderId": "1234-5678",
            //         "timeInForce": "IOC",
            //         "postOnly": false,
            //         "selfTrade": "P",
            //         "triggerAmount": "105",
            //         "targetAmount": "1000"
            //     }
            //
            return this.parseOrder(response, market);
        });

    }

    /**
     * @method
     * @name btcmarkets#cancelOrders
     * @description cancel multiple orders
     * @see https://docs.btcmarkets.net/v3/#tag/Batch-Order-APIs/paths/~1v3~1batchorders~1{ids}/delete
     * @param {string[]} ids order ids
     * @param {string} symbol not used by btcmarkets cancelOrders ()
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> cancelOrders(Object ids, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object numericIds = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(ids)); i++)
            {
                // numericIds[i] = parseInt (ids[i]);
                ((java.util.List<Object>)numericIds).add(Helpers.parseInt(Helpers.GetValue(ids, i)));
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "ids", numericIds );
            }};
            Object response = (this.privateDeleteBatchordersIds(this.extend(request, parameters))).join();
            //
            //    {
            //       "cancelOrders": [
            //            {
            //               "orderId": "414186",
            //               "clientOrderId": "6"
            //            },
            //            ...
            //        ],
            //        "unprocessedRequests": [
            //            {
            //               "code": "OrderAlreadyCancelled",
            //               "message": "order is already cancelled.",
            //               "requestId": "1"
            //            }
            //        ]
            //    }
            //
            Object cancelOrders = this.safeList(response, "cancelOrders", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object unprocessedRequests = this.safeList(response, "unprocessedRequests", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object orders = this.arrayConcat(cancelOrders, unprocessedRequests);
            return this.parseOrders(orders);
        });

    }

