    public Object calculateFee(Object symbol, Object type, Object side, Object amount, Object price, Object... optionalArgs)
    {
        /**
        * @method
        * @description calculates the presumptive fee that would be charged for an order
        * @param {string} symbol unified market symbol
        * @param {string} type not used by btcmarkets.calculateFee
        * @param {string} side not used by btcmarkets.calculateFee
        * @param {float} amount how much you want to trade, in units of the base currency on most exchanges, or number of contracts
        * @param {float} price the price for the order to be filled at, in units of the quote currency
        * @param {string} takerOrMaker 'taker' or 'maker'
        * @param {object} params
        * @returns {object} contains the rate, the percentage multiplied to the order amount to obtain the fee amount, and cost, the total value of the fee in units of the quote currency, for the order
        */
        Object takerOrMaker = Helpers.getArg(optionalArgs, 0, "taker");
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object market = Helpers.GetValue(this.markets, symbol);
        Object currency = null;
        Object cost = null;
        if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(market, "quote"), "AUD")))
        {
            currency = Helpers.GetValue(market, "quote");
            Object amountString = this.numberToString(amount);
            Object priceString = this.numberToString(price);
            Object otherUnitsAmount = Precise.stringMul(amountString, priceString);
            cost = this.costToPrecision(symbol, otherUnitsAmount);
        } else
        {
            currency = Helpers.GetValue(market, "base");
            cost = this.amountToPrecision(symbol, amount);
        }
        Object rate = Helpers.GetValue(market, takerOrMaker);
        Object rateCost = Precise.stringMul(this.numberToString(rate), cost);
        final Object finalCurrency = currency;
        return new java.util.HashMap<String, Object>() {{
            put( "type", takerOrMaker );
            put( "currency", finalCurrency );
            put( "rate", rate );
            put( "cost", Helpers.parseFloat(BtcmarketsCore.this.feeToPrecision(symbol, rateCost)) );
        }};
    }

    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "Accepted", "open" );
            put( "Placed", "open" );
            put( "Partially Matched", "open" );
            put( "Fully Matched", "closed" );
            put( "Cancelled", "canceled" );
            put( "Partially Cancelled", "canceled" );
            put( "Failed", "rejected" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder
        //
        //     {
        //         "orderId": "7524",
        //         "marketId": "BTC-AUD",
        //         "side": "Bid",
        //         "type": "Limit",
        //         "creationTime": "2019-08-30T11:08:21.956000Z",
        //         "price": "100.12",
        //         "amount": "1.034",
        //         "openAmount": "1.034",
        //         "status": "Accepted",
        //         "clientOrderId": "1234-5678",
        //         "timeInForce": "IOC",
        //         "postOnly": false,
        //         "selfTrade": "P",
        //         "triggerAmount": "105",
        //         "targetAmount": "1000"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(order, "creationTime"));
        Object marketId = this.safeString(order, "marketId");
        market = this.safeMarket(marketId, market, "-");
        Object side = this.safeString(order, "side");
        if (Helpers.isTrue(Helpers.isEqual(side, "Bid")))
        {
            side = "buy";
        } else if (Helpers.isTrue(Helpers.isEqual(side, "Ask")))
        {
            side = "sell";
        }
        Object type = this.safeStringLower(order, "type");
        Object price = this.safeString(order, "price");
        Object amount = this.safeString(order, "amount");
        Object remaining = this.safeString(order, "openAmount");
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        Object id = this.safeString(order, "orderId");
        Object clientOrderId = this.safeString(order, "clientOrderId");
        Object timeInForce = this.safeString(order, "timeInForce");
        Object postOnly = this.safeBool(order, "postOnly");
        final Object finalMarket = market;
        final Object finalSide = side;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", BtcmarketsCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", type );
            put( "timeInForce", timeInForce );
            put( "postOnly", postOnly );
            put( "side", finalSide );
            put( "price", price );
            put( "triggerPrice", BtcmarketsCore.this.safeNumber(order, "triggerPrice") );
            put( "cost", null );
            put( "amount", amount );
            put( "filled", null );
            put( "remaining", remaining );
            put( "average", null );
            put( "status", status );
            put( "trades", null );
            put( "fee", null );
        }}, market);
    }

